//! End-to-end tests for TesseraContract contract.
//!
//! Spawns a local Anvil node, deploys PoseidonGoldilocks + TesseraContract with
//! AcceptAllVerifier (no real Groth16 required), and exercises the two-phase
//! proving protocol using Rust-native piCommitment computation.
//!
//! Tests:
//! 1. `test_e2e_tx_batch`                          — single TX batch, root updated.
//! 2. `test_e2e_second_batch_references_first_root` — root history chaining.
//! 3. `test_e2e_deposit_batch`                      — deposit lifecycle.
//! 4. `test_e2e_invalid_root_rejected`              — unconfirmed acRoot reverts.

use alloy::{
	network::{EthereumWallet, TransactionBuilder},
	node_bindings::{Anvil, AnvilInstance},
	primitives::{keccak256, Address, Bytes, B256, U256},
	providers::{Provider, ProviderBuilder},
	rpc::types::TransactionRequest,
	signers::local::PrivateKeySigner,
	sol,
	sol_types::SolValue,
};
use plonky2::field::types::Field;
use tessera_server::{
	contract::{hash_to_u256_le, ITesseraRollupV2},
	proof_aggregation::SubtreeRootCircuit,
};
use tessera_utils::{hasher::HashOutput, F};

const ACCEPT_BYTECODE: &str = "";
const REJECT_BYTECODE: &str = "";
const POSEIDON_BYTECODE: &str = "";
const ROLLUP_BYTECODE: &str = "";
const TOKEN_BYTECODE: &str = "";

// ---------------------------------------------------------------------------
// Minimal ToyUSDT sol! binding for tests.
// ---------------------------------------------------------------------------

sol! {
	#[sol(rpc)]
	interface IToyUSDT {
		function mint(address to, uint256 value) external;
		function approve(address spender, uint256 value) external returns (bool);
		function balanceOf(address account) external view returns (uint256);
	}
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const N_NC: usize = 16; // 2 slots × 8 notes
const TREE_DEPTH_VAL: u64 = 4;
// bytes32(uint256(0xC0FFEE)) — right-justified big-endian
const PCR: [u8; 32] = {
	let mut b = [0u8; 32];
	b[29] = 0xC0;
	b[30] = 0xFF;
	b[31] = 0xEE;
	b
};

// ---------------------------------------------------------------------------
// Deployment helpers
// ---------------------------------------------------------------------------

/// Deploy a contract from hex-encoded bytecode with no constructor args.
async fn deploy_no_args<P: Provider + Clone>(provider: &P, bytecode_hex: &str) -> Address {
	let bytecode = Bytes::from(hex::decode(bytecode_hex).expect("hex decode"));
	let tx = TransactionRequest::default().with_deploy_code(bytecode);
	provider
		.send_transaction(tx)
		.await
		.expect("deploy_no_args send")
		.get_receipt()
		.await
		.expect("deploy_no_args receipt")
		.contract_address
		.expect("no contract_address in receipt")
}

/// Deploy a contract with ABI-encoded constructor args appended to the bytecode.
async fn deploy_with_args<P: Provider + Clone>(
	provider: &P,
	bytecode_hex: &str,
	constructor_args: Vec<u8>,
) -> Address {
	let mut bytecode = hex::decode(bytecode_hex).expect("hex decode");
	bytecode.extend_from_slice(&constructor_args);
	let tx = TransactionRequest::default().with_deploy_code(Bytes::from(bytecode));
	provider
		.send_transaction(tx)
		.await
		.expect("deploy_with_args send")
		.get_receipt()
		.await
		.expect("deploy_with_args receipt")
		.contract_address
		.expect("no contract_address in receipt")
}

// ---------------------------------------------------------------------------
// piCommitment native computations (must match on-chain Solidity exactly)
// ---------------------------------------------------------------------------

/// keccak256(root | mainPoolConfigRoot | batchPoseidonRoot |
///           accountCommitments[..] | accountNullifiers[..] |
///           noteCommitments[..] | noteNullifiers[..])
///
/// Each uint256 is encoded as 32 big-endian bytes; bytes32 is passed as-is.
fn compute_tx_pi_commitment(
	root: U256,
	pool_config_root: [u8; 32],
	batch_poseidon_root: U256,
	account_commitments: &[U256],
	account_nullifiers: &[U256],
	note_commitments: &[U256],
	note_nullifiers: &[U256],
) -> B256 {
	let mut pre: Vec<u8> = Vec::new();
	pre.extend_from_slice(&root.to_be_bytes::<32>());
	pre.extend_from_slice(&pool_config_root);
	pre.extend_from_slice(&batch_poseidon_root.to_be_bytes::<32>());
	for ac in account_commitments {
		pre.extend_from_slice(&ac.to_be_bytes::<32>());
	}
	for an in account_nullifiers {
		pre.extend_from_slice(&an.to_be_bytes::<32>());
	}
	for nc in note_commitments {
		pre.extend_from_slice(&nc.to_be_bytes::<32>());
	}
	for nn in note_nullifiers {
		pre.extend_from_slice(&nn.to_be_bytes::<32>());
	}
	keccak256(&pre)
}

/// keccak256(acRoot | ncRoot | mainPoolConfigRoot | batchPoseidonRoot |
///           ethAddresses[..] as 5×u32 LE limbs each)
///
/// Matches `_computeDepositPiCommitment` in TesseraContract.sol and the
/// `DepositSuperAggregatorV2` Keccak preimage in the prover.
fn compute_deposit_pi_commitment(
	root: U256,
	pool_config_root: [u8; 32],
	batch_poseidon_root: U256,
	eth_addresses: &[Address],
) -> B256 {
	let mut pre: Vec<u8> = Vec::new();
	pre.extend_from_slice(&root.to_be_bytes::<32>());
	eprintln!(
		"[E2E-NATIVE] root              bytes: {}",
		hex::encode(&root.to_be_bytes::<32>())
	);
	pre.extend_from_slice(&pool_config_root);
	eprintln!(
		"[E2E-NATIVE] mainPoolCfgRoot   bytes: {}",
		hex::encode(&pool_config_root)
	);
	pre.extend_from_slice(&batch_poseidon_root.to_be_bytes::<32>());
	eprintln!(
		"[E2E-NATIVE] batchPoseidonRoot bytes: {}",
		hex::encode(&batch_poseidon_root.to_be_bytes::<32>())
	);
	// Each address is serialised as 5 × u32 LE limbs (matching map_h160_to_f).
	// The Keccak gadget emits each u32 as BE bytes, so each 4-byte chunk is reversed.
	// Pad to DEPOSIT_BATCH_SIZE (512) to match the circuit's fixed width.
	const DEPOSIT_BATCH_SIZE: usize = 512;
	for i in 0..DEPOSIT_BATCH_SIZE {
		let addr = if i < eth_addresses.len() {
			eth_addresses[i]
		} else {
			Address::ZERO
		};
		let bytes = addr.as_slice(); // 20 bytes, big-endian
		let mut addr_encoded = Vec::new();
		for chunk in bytes.chunks(4) {
			let limb = u32::from_le_bytes(chunk.try_into().unwrap());
			let be = limb.to_be_bytes();
			addr_encoded.extend_from_slice(&be);
			pre.extend_from_slice(&be);
		}
		if i < 3 || i == DEPOSIT_BATCH_SIZE - 1 {
			eprintln!(
				"[E2E-NATIVE] ethAddr[{:>3}]      bytes: {}",
				i,
				hex::encode(&addr_encoded)
			);
		}
	}
	eprintln!(
		"[E2E-NATIVE] total addrs: {}, preimage len: {}",
		DEPOSIT_BATCH_SIZE,
		pre.len()
	);
	let h = keccak256(&pre);
	eprintln!("[E2E-NATIVE] keccak result: {}", hex::encode(h));
	h
}

// ---------------------------------------------------------------------------
// Synthetic batch data
// ---------------------------------------------------------------------------

fn make_nc_leaves() -> Vec<HashOutput> {
	(0..N_NC)
		.map(|i| {
			HashOutput::new([
				F::from_canonical_u64(i as u64 + 1),
				F::ZERO,
				F::ZERO,
				F::ZERO,
			])
		})
		.collect()
}

fn make_nc_leaves_2() -> Vec<HashOutput> {
	(0..N_NC)
		.map(|i| {
			HashOutput::new([
				F::from_canonical_u64(100 + i as u64),
				F::ZERO,
				F::ZERO,
				F::ZERO,
			])
		})
		.collect()
}

// ---------------------------------------------------------------------------
// Test fixture
// ---------------------------------------------------------------------------

struct TestEnv {
	rollup: Address,
	token: Address,
	operator: Address,
	genesis_root: U256,
	/// Keeps the Anvil process alive for the duration of the test.
	_anvil: AnvilInstance,
}

/// Spawn Anvil, deploy all contracts, return addresses + genesis root.
async fn setup(reject_tx: bool) -> (TestEnv, impl Provider + Clone) {
	let anvil: AnvilInstance = Anvil::new().try_spawn().expect("anvil spawn");
	let signer: PrivateKeySigner = anvil.keys()[0].clone().into();
	let operator = signer.address();
	let wallet = EthereumWallet::from(signer);
	let provider = ProviderBuilder::new()
		.wallet(wallet)
		.connect_http(anvil.endpoint_url());

	let accept_addr = deploy_no_args(&provider, ACCEPT_BYTECODE).await;
	let reject_addr = deploy_no_args(&provider, REJECT_BYTECODE).await;
	let poseidon_addr = deploy_no_args(&provider, POSEIDON_BYTECODE).await;
	let token_addr = deploy_no_args(&provider, TOKEN_BYTECODE).await;

	let tx_verifier_addr = if reject_tx { reject_addr } else { accept_addr };

	// TesseraContract constructor:
	//   (address txVerifier, address depositVerifier, address poseidon,
	//    address operator, address monitoredToken, bytes32 poolConfigRoot, uint256 treeDepth)
	let constructor_args = (
		tx_verifier_addr,
		accept_addr,
		poseidon_addr,
		operator,
		token_addr,
		B256::from(PCR),
		U256::from(TREE_DEPTH_VAL),
	)
		.abi_encode();

	let rollup_addr = deploy_with_args(&provider, ROLLUP_BYTECODE, constructor_args).await;

	// Read genesis root.
	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(rollup_addr, &provider);
	let genesis_root = rollup.currentRoot().call().await.expect("currentRoot");

	(
		TestEnv {
			rollup: rollup_addr,
			token: token_addr,
			operator,
			genesis_root,
			_anvil: anvil,
		},
		provider,
	)
}

// ---------------------------------------------------------------------------
// Protocol helpers — create instance inside each helper
// ---------------------------------------------------------------------------

/// Submit a TX batch and assert the event piCommitment matches our native computation.
/// Returns the on-chain piCommitment bytes32.
async fn submit_tx_batch<P: Provider + Clone>(
	rollup_addr: Address,
	provider: &P,
	root: U256,
	nc_leaves: &[HashOutput],
	account_commitment: U256,
	account_nullifier: U256,
) -> B256 {
	let batch_poseidon_root = hash_to_u256_le(&SubtreeRootCircuit::compute_root_native(nc_leaves));
	let note_commitments: Vec<U256> = nc_leaves.iter().map(hash_to_u256_le).collect();
	let note_nullifiers: Vec<U256> = vec![];
	let account_commitments = vec![account_commitment];
	let account_nullifiers = vec![account_nullifier];

	let expected_pi = compute_tx_pi_commitment(
		root,
		PCR,
		batch_poseidon_root,
		&account_commitments,
		&account_nullifiers,
		&note_commitments,
		&note_nullifiers,
	);

	let batch = ITesseraRollupV2::TransactionBatch {
		root,
		mainPoolConfigRoot: B256::from(PCR),
		noteCommitments: note_commitments,
		noteNullifiers: note_nullifiers,
		accountCommitments: account_commitments,
		accountNullifiers: account_nullifiers,
		batchPoseidonRoot: batch_poseidon_root,
		confirmed: false,
	};

	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(rollup_addr, provider);
	let receipt = rollup
		.submitTransactionBatch(batch)
		.send()
		.await
		.expect("submitTransactionBatch send")
		.get_receipt()
		.await
		.expect("submitTransactionBatch receipt");
	assert!(receipt.status(), "submitTransactionBatch reverted");

	let on_chain_pi: B256 = receipt
		.inner
		.logs()
		.iter()
		.find_map(|l| {
			l.log_decode::<ITesseraRollupV2::TransactionBatchSubmitted>()
				.ok()
				.map(|d| d.inner.piCommitment)
		})
		.expect("TransactionBatchSubmitted event not found");

	assert_eq!(
		on_chain_pi, expected_pi,
		"on-chain piCommitment differs from native Rust computation"
	);
	on_chain_pi
}

/// Prove a submitted TX batch (zero Groth16 proof, AcceptAllVerifier accepts).
/// Returns the new confirmed tree root from the emitted event.
async fn prove_tx_batch<P: Provider + Clone>(
	rollup_addr: Address,
	provider: &P,
	pi_commitment: B256,
) -> U256 {
	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(rollup_addr, provider);
	let zero_proof = ITesseraRollupV2::Proof {
		proof: [U256::ZERO; 8],
		commitments: [U256::ZERO; 2],
		commitmentPok: [U256::ZERO; 2],
	};
	let receipt = rollup
		.proveTransactionBatch(pi_commitment, zero_proof)
		.send()
		.await
		.expect("proveTransactionBatch send")
		.get_receipt()
		.await
		.expect("proveTransactionBatch receipt");
	assert!(receipt.status(), "proveTransactionBatch reverted");

	receipt
		.inner
		.logs()
		.iter()
		.find_map(|l| {
			l.log_decode::<ITesseraRollupV2::TransactionBatchProven>()
				.ok()
				.map(|d| d.inner.newTreeRoot)
		})
		.expect("TransactionBatchProven event not found")
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

/// Test 1: single TX batch — batchPoseidonRoot appended, new root confirmed.
#[tokio::test]
async fn test_e2e_tx_batch() {
	let (env, provider) = setup(false).await;

	let pi = submit_tx_batch(
		env.rollup,
		&provider,
		env.genesis_root,
		&make_nc_leaves(),
		U256::from(0x1000u64),
		U256::from(0x2000u64),
	)
	.await;

	let new_root = prove_tx_batch(env.rollup, &provider, pi).await;

	assert_ne!(new_root, env.genesis_root, "root must change after batch");

	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(env.rollup, &provider);

	let confirmed = rollup
		.confirmedRoots(new_root)
		.call()
		.await
		.expect("confirmedRoots");
	assert!(confirmed, "new root must be in confirmedRoots");

	let current: U256 = rollup.currentRoot().call().await.expect("currentRoot");
	assert_eq!(current, new_root, "currentRoot must equal new_root");
}

/// Test 2: second batch references the root confirmed by the first batch.
#[tokio::test]
async fn test_e2e_second_batch_references_first_root() {
	let (env, provider) = setup(false).await;

	// First batch.
	let pi1 = submit_tx_batch(
		env.rollup,
		&provider,
		env.genesis_root,
		&make_nc_leaves(),
		U256::from(0x1001u64),
		U256::from(0x2001u64),
	)
	.await;
	let root1 = prove_tx_batch(env.rollup, &provider, pi1).await;

	// Second batch uses root1.
	let pi2 = submit_tx_batch(
		env.rollup,
		&provider,
		root1,
		&make_nc_leaves_2(),
		U256::from(0x1002u64),
		U256::from(0x2002u64), // distinct nullifier
	)
	.await;
	let root2 = prove_tx_batch(env.rollup, &provider, pi2).await;

	assert_ne!(root1, root2, "consecutive roots must differ");

	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(env.rollup, &provider);
	let c1: bool = rollup
		.confirmedRoots(root1)
		.call()
		.await
		.expect("confirmedRoots r1");
	let c2: bool = rollup
		.confirmedRoots(root2)
		.call()
		.await
		.expect("confirmedRoots r2");
	assert!(c1, "root1 must remain confirmed");
	assert!(c2, "root2 must be confirmed");
}

/// Test 3: deposit batch lifecycle — Pending → Validated, root advances.
#[tokio::test]
async fn test_e2e_deposit_batch() {
	let (env, provider) = setup(false).await;
	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(env.rollup, &provider);
	let token = IToyUSDT::IToyUSDTInstance::new(env.token, &provider);

	// Mint and approve.
	let mint_amount = U256::from(1_000_000u64);
	token
		.mint(env.operator, mint_amount)
		.send()
		.await
		.unwrap()
		.get_receipt()
		.await
		.unwrap();
	token
		.approve(env.rollup, mint_amount)
		.send()
		.await
		.unwrap()
		.get_receipt()
		.await
		.unwrap();

	// Register a deposit.
	let deposit_nc = B256::from([0x42u8; 32]);
	let dep_receipt = rollup
		.depositAndRegister(deposit_nc, U256::from(100u64))
		.send()
		.await
		.expect("depositAndRegister send")
		.get_receipt()
		.await
		.expect("depositAndRegister receipt");
	assert!(dep_receipt.status(), "depositAndRegister reverted");

	let dep = rollup
		.getDeposit(deposit_nc)
		.call()
		.await
		.expect("getDeposit");
	assert!(matches!(
		dep.status,
		ITesseraRollupV2::DepositStatus::Pending
	));

	// Build deposit batch piCommitment.
	// The depositor is env.operator (msg.sender of depositAndRegister).
	let depositor = env.operator;
	let batch_poseidon_root = U256::from(0xDEAD_BEEFu64); // arbitrary non-zero
	let expected_pi =
		compute_deposit_pi_commitment(env.genesis_root, PCR, batch_poseidon_root, &[depositor]);

	// Submit deposit batch (operator-only).
	let deposit_batch = ITesseraRollupV2::DepositBatch {
		root: env.genesis_root,
		mainPoolConfigRoot: B256::from(PCR),
		depositNoteCommitments: vec![deposit_nc],
		batchPoseidonRoot: batch_poseidon_root,
		confirmed: false,
	};
	let sub_receipt = rollup
		.submitDepositBatch(deposit_batch)
		.send()
		.await
		.expect("submitDepositBatch send")
		.get_receipt()
		.await
		.expect("submitDepositBatch receipt");
	assert!(sub_receipt.status(), "submitDepositBatch reverted");

	// Decode and print the debug preimage from Solidity.
	if let Some(debug) = sub_receipt.inner.logs().iter().find_map(|l| {
		l.log_decode::<ITesseraRollupV2::DebugDepositPreimage>()
			.ok()
	}) {
		let preimage = &debug.inner.preimage;
		let result = debug.inner.result;
		eprintln!("\n[SOLIDITY] preimage len: {}", preimage.len());
		// root (32 bytes)
		eprintln!(
			"[SOLIDITY] root              bytes: {}",
			hex::encode(&preimage[..32])
		);
		// mainPoolConfigRoot (32 bytes)
		eprintln!(
			"[SOLIDITY] mainPoolCfgRoot   bytes: {}",
			hex::encode(&preimage[32..64])
		);
		// batchPoseidonRoot (32 bytes)
		eprintln!(
			"[SOLIDITY] batchPoseidonRoot bytes: {}",
			hex::encode(&preimage[64..96])
		);
		// ethAddresses: 20 bytes each, starting at offset 96
		let addr_data = &preimage[96..];
		let n_addrs = addr_data.len() / 20;
		for i in 0..n_addrs.min(3) {
			eprintln!(
				"[SOLIDITY] ethAddr[{:>3}]      bytes: {}",
				i,
				hex::encode(&addr_data[i * 20..(i + 1) * 20])
			);
		}
		if n_addrs > 3 {
			eprintln!(
				"[SOLIDITY] ethAddr[{:>3}]      bytes: {}",
				n_addrs - 1,
				hex::encode(&addr_data[(n_addrs - 1) * 20..n_addrs * 20])
			);
		}
		eprintln!("[SOLIDITY] total addrs: {}", n_addrs);
		eprintln!("[SOLIDITY] keccak result: {}", hex::encode(result));
	}

	// Verify on-chain piCommitment matches native.
	let on_chain_pi: B256 = sub_receipt
		.inner
		.logs()
		.iter()
		.find_map(|l| {
			l.log_decode::<ITesseraRollupV2::DepositBatchSubmitted>()
				.ok()
				.map(|d| d.inner.piCommitment)
		})
		.expect("DepositBatchSubmitted event not found");
	assert_eq!(on_chain_pi, expected_pi, "deposit piCommitment mismatch");

	// Prove deposit batch.
	let zero_proof = ITesseraRollupV2::Proof {
		proof: [U256::ZERO; 8],
		commitments: [U256::ZERO; 2],
		commitmentPok: [U256::ZERO; 2],
	};
	let prove_receipt = rollup
		.proveDepositBatch(on_chain_pi, zero_proof)
		.send()
		.await
		.expect("proveDepositBatch send")
		.get_receipt()
		.await
		.expect("proveDepositBatch receipt");
	assert!(prove_receipt.status(), "proveDepositBatch reverted");

	// Deposit note must be Validated.
	let dep_after = rollup
		.getDeposit(deposit_nc)
		.call()
		.await
		.expect("getDeposit after");
	assert!(matches!(
		dep_after.status,
		ITesseraRollupV2::DepositStatus::Validated
	));

	// Root must advance.
	let new_root: U256 = rollup.currentRoot().call().await.expect("currentRoot");
	assert_ne!(new_root, env.genesis_root, "root must advance");
	let confirmed: bool = rollup
		.confirmedRoots(new_root)
		.call()
		.await
		.expect("confirmedRoots");
	assert!(confirmed, "new root must be confirmed");
}

/// Test 4: submitTransactionBatch with an unconfirmed acRoot must revert.
#[tokio::test]
async fn test_e2e_invalid_root_rejected() {
	let (env, provider) = setup(false).await;
	let rollup = ITesseraRollupV2::ITesseraRollupV2Instance::new(env.rollup, &provider);

	let nc_leaves = make_nc_leaves();
	let batch_poseidon_root = hash_to_u256_le(&SubtreeRootCircuit::compute_root_native(&nc_leaves));
	let note_commitments: Vec<U256> = nc_leaves.iter().map(hash_to_u256_le).collect();

	// bad_root is NOT in confirmedRoots.
	let bad_root = U256::from(0xBAAD_F00Du64);

	let batch = ITesseraRollupV2::TransactionBatch {
		root: bad_root,
		mainPoolConfigRoot: B256::from(PCR),
		noteCommitments: note_commitments,
		noteNullifiers: vec![],
		accountCommitments: vec![U256::from(1u64)],
		accountNullifiers: vec![U256::from(2u64)],
		batchPoseidonRoot: batch_poseidon_root,
		confirmed: false,
	};

	let result = rollup.submitTransactionBatch(batch).send().await;
	assert!(
		result.is_err(),
		"submitTransactionBatch with bad acRoot must revert"
	);
}
